var val = Services.getValue(AmntPaidChildDependant.dataBinding);
var err = validateCurrencyValue(val, 99999999.99);
if( null == err )
{	Services.setValue(AmntPaidChildDependant.dataBinding, WPU.formatToTwoDP(val));
}
return err;

