Javascript.miscCode:
function DefaultCurrency605() {}
DefaultCurrency605.dataBinding = "/ds/EnterVariableData/curr1";
DefaultCurrency605.tabIndex = -1;
DefaultCurrency605.maxLength = 1;
DefaultCurrency605.isReadOnly = function(){return true;}
DefaultCurrency605.isTemporary = function(){return true;}
DefaultCurrency605.transformToDisplay = function(value){
	return WPS.__CaseManUtils().transformCurrencySymbolToDisplay(value,null,null); }
DefaultCurrency605.transformToModel = function(value){
	return WPS.__CaseManUtils().transformCurrencySymbolToModel(value,null,null); }
